INSERT INTO coaching.phase_order_slot (key, name, description, phase_id, order_index, freshness_sensitivity, subrole_key)
SELECT v.key, v.name, v.description, sp.id, v.order_index, v.freshness_sensitivity, v.subrole_key
FROM coaching.session_phase sp
CROSS JOIN (VALUES
  ('hip_mobility', 'Hip Mobility', 'Legacy coarse hip slot (superseded by fine slots).', 135, 1, 'mobilize'),
  ('glute_activation', 'Glute Activation', 'Bridges, clams, and glute engagement drills.', 137, 2, 'activate'),
  ('glute_core_integration', 'Glute / Core Integration', 'Bridge march and pelvic-control progressions.', 138, 2, 'activate'),
  ('core_activation', 'Core Activation', 'Dead bug and anti-extension drills.', 139, 2, 'activate'),
  ('lateral_hip_activation', 'Lateral Hip Activation', 'Mini-band walks and glute medius prep.', 140, 2, 'activate'),
  ('integrated_mobility', 'Integrated Mobility', 'Multi-joint mobility flowing through ranges.', 165, 2, 'integrate'),
  ('cross_body_core', 'Cross-Body Core', 'Bird dog and contralateral trunk integration.', 151, 2, 'integrate'),
  ('marching_mechanics', 'Marching Mechanics', 'A-march, B-march, and sprint posture drills.', 160, 2, 'potentiate_bridge')
) AS v(key, name, description, order_index, freshness_sensitivity, subrole_key)
WHERE sp.key = 'prepare_access'
ON CONFLICT (key) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  phase_id = EXCLUDED.phase_id,
  order_index = EXCLUDED.order_index,
  freshness_sensitivity = EXCLUDED.freshness_sensitivity,
  subrole_key = EXCLUDED.subrole_key;

