  movement_requirements = '{"primary_joint_actions":["hip_flexion","ankle_dorsiflexion"],"primary_tissues":[],"breathing_demand":"nasal","balance_demand":"stable","impact_level":1}'::jsonb,
  coaching_execution = '{"movement_description":"March forward slowly with tall posture. Lift one knee to roughly hip height, keep the toe pulled up, coordinate opposite arm swing, and step down under the hip with control. Repeat rhythmically.","setup":["Stand tall.","Eyes forward.","Ribs stacked over pelvis.","Arms bent around 90 degrees.","Feet under hips."],"execution_steps":["Lift one knee to hip height or appropriate range.","Pull toe up toward shin.","Keep heel under knee.","Opposite arm moves forward.","Step down under the hip.","Alternate sides with rhythm."],"breathing_cues":["Breathe rhythmically.","Stay relaxed through face and shoulders."],"coach_cues":["Tall posture.","Knee up, toe up.","Step down under the hip.","Opposite arm, opposite leg.","Smooth rhythm before speed."],"athlete_cues":["Tall.","Knee up.","Toe up.","Step down.","Find the beat."],"common_faults":["Leaning backward.","Collapsing posture.","Toe pointing down.","Foot striking too far in front.","Arms crossing the body.","Marching too fast before mechanics are clean."],"stop_signs":["Hip flexor pinching.","Knee pain.","Ankle pain.","Loss of balance.","Coordination breaks down completely."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Glute Bridge","Bridge March","Dead Bug","Foot Tripod Weight Shifts","Leg Swings","Walking Knee Hug"],"pairs_well_after":["Sprint mechanics","Acceleration wall drill","A-Skip","Low Pogos","Agility prep","Tumbling takeoff prep"],"good_for_sessions":["sprint_prep","landing_prep","general_warmup","tumbling_prep"],"avoid_before":["Max sprinting if posture, dorsiflexion, or rhythm are poor","Fast agility if foot contacts are sloppy"],"avoid_after":[],"do_not_use_when":["Hip flexor pain worsens","Balance is unsafe","Athlete cannot coordinate marching without frustration or breakdown"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["SimpliFaster A-March Coaching Cues","Parisi School A-March / A-Skip / A-Run Progression","Chris Johnson PT Marching Drills"],"internal_notes":["Start with smooth rhythm before changing tempo."]}'::jsonb,
  updated_at = now()
WHERE slug = 'a-march';

UPDATE coaching.exercise_phase_profile p SET
  role = 'primary',
  order_slot = 'marching_mechanics',
  order_index = pos.order_index,
  fit_weight = 5,
  freshness_required = FALSE,
  fatigue_sensitivity = 3,
  fatigue_cost = 1,
  technical_complexity = 4,
  impact_level = 1,
  intensity_ceiling = 'moderate',
  notes = 'Prepare / Access version is slow and technical. Faster, more coached versions belong in Skill / Movement Intelligence.'
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'prepare_access'
JOIN coaching.phase_order_slot pos ON pos.key = 'marching_mechanics' AND pos.phase_id = sp.id
WHERE p.exercise_id = e.id AND p.phase_id = sp.id AND e.slug = 'a-march';

UPDATE coaching.exercise_dosage_profile d SET
  volume_unit = 'distance',
  default_sets = 1,
  default_reps = NULL,
  default_distance = 12,
  default_work_seconds = 20,
  default_rest_seconds = 0,
  est_seconds_per_set = 30,
  default_rpe_min = 2,
  default_rpe_max = 4,
  session_volume_min = '10',
  session_volume_max = '30'
FROM coaching.exercise e
WHERE d.exercise_id = e.id AND d.profile_name = 'Default' AND e.slug = 'a-march';

UPDATE coaching.exercise_regimen_rule r SET
  can_be_daily = TRUE,
  weekly_max_frequency = CASE WHEN TRUE THEN 7 ELSE r.weekly_max_frequency END
FROM coaching.exercise e
WHERE r.exercise_id = e.id AND e.slug = 'a-march';

