UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('glute-bridge', 'Use simple cue: "push the floor, squeeze your glutes." Keep reps low.', 'No sex-based default. Scale by trunk control, hip control, coordination, sport demand, and symptoms.'),
  ('glute-bridge-march', 'Stay with regular glute bridge until hips stay level.', 'No sex-based default. Scale by trunk control, hip control, coordination, sport demand, and symptoms.'),
  ('dead-bug-heel-tap', 'Use heel taps from feet-on-floor position.', 'No sex-based default. Scale by trunk control, hip control, coordination, sport demand, and symptoms.'),
  ('bird-dog', 'Start with only leg reach or only arm reach.', 'No sex-based default. Scale by trunk control, hip control, coordination, sport demand, and symptoms.'),
  ('mini-band-lateral-walk', 'No band first; lateral step with knee-track cue.', 'No sex-based default. Scale by trunk control, hip control, coordination, sport demand, and symptoms.'),
  ('a-march', 'March in place first; use "knee up, toe up" rhythm game.', 'No sex-based default. Scale by trunk control, hip control, coordination, sport demand, and symptoms.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'youth_beginner';

