UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'teen' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('glute-bridge', 'Adjust foot position to reduce hamstring cramping. Emphasize rib-pelvis control and avoid overextending at the top.', 'No sex-based default. Scale by trunk control, hip control, coordination, sport demand, and symptoms.'),
  ('glute-bridge-march', 'Use hands on hips to feel pelvic movement. Keep range small and controlled; avoid excessive lumbar extension.', 'No sex-based default. Scale by trunk control, hip control, coordination, sport demand, and symptoms.'),
  ('dead-bug-heel-tap', 'Reduce range; stop before back arches. Focus on active rib-pelvis control; avoid excessive spinal flattening or gripping.', 'No sex-based default. Scale by trunk control, hip control, coordination, sport demand, and symptoms.'),
  ('bird-dog', 'Widen knees and hands for stability. Emphasize active trunk control and avoid sagging into shoulders/spine.', 'No sex-based default. Scale by trunk control, hip control, coordination, sport demand, and symptoms.'),
  ('mini-band-lateral-walk', 'Band above knees or ankles; small controlled steps. Emphasize active hip/knee control and avoid collapsing into knee valgus.', 'No sex-based default. Scale by trunk control, hip control, coordination, sport demand, and symptoms.'),
  ('a-march', 'Slow tempo and lower knee height if hip flexors dominate. Emphasize controlled knee lift and foot strike under center; avoid floppy contacts.', 'No sex-based default. Scale by trunk control, hip control, coordination, sport demand, and symptoms.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
