  ('dead-bug-heel-tap', 'Add opposite arm reach or band-resisted dead bug, but avoid fatigue before Output.', 'No sex-based default. Scale by trunk control, hip control, coordination, sport demand, and symptoms.'),
  ('bird-dog', 'Add bird-dog squares or elbow-to-knee, but keep warm-up dose low.', 'No sex-based default. Scale by trunk control, hip control, coordination, sport demand, and symptoms.'),
  ('mini-band-lateral-walk', 'Band at feet or double-band only if not fatiguing.', 'No sex-based default. Scale by trunk control, hip control, coordination, sport demand, and symptoms.'),
  ('a-march', 'Progress to A-skip, wall-drill exchange, or acceleration mechanics in the next phase.', 'No sex-based default. Scale by trunk control, hip control, coordination, sport demand, and symptoms.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'adult_advanced';

